('4f18ce15-51ee-41bd-8fc4-e3b8097b3e40', '64ed428e-10b7-428e-b584-e3b6378cb171', 'Fish stew', 'main', 'Fish, tomato sauce, broth', '', '<p><strong><span style="text-decoration: underline;">Ingredients</span></strong></p>
<ul>
<li>onion</li>
<li>garlic</li>
<li>thyme&nbsp;</li>
<li>CRP</li>
<li>diced tomatoes&nbsp;</li>
<li>crushed tomatoes</li>
<li>stock</li>
<li>red wine</li>
<li>fish (already cooked)</li>
<li>salt and pepper</li>
<li>shrimp &amp; scallop</li>
<li>lemon</li>
<li>parsley&nbsp;</li>
<li>basil</li>
</ul>
<p>&nbsp;</p>
<p><span style="text-decoration: underline;"><strong>Instructions:</strong></span></p>
<ul>
<li>cut onions, garlic, basil, parsely, thyme&nbsp;</li>
<li>pan fry salmon (salt &amp; pepper)</li>
<li>sautee onions, add garlic, then thyme, crp,&nbsp;</li>
<li>add tomatoes</li>
<li>add stock and red wine</li>
<li>simmer for 45 mins</li>
<li>add fish and then season with S&amp;P</li>
<li>add shrimp and scallop</li>
<li>lemon juice</li>
<li>add parsley and basil</li>
</ul>', false),
